const from = new Date();
const to = new Date();
to.setDate(to.getDate() + 2);
const fromStr = from.toISOString().split('T')[0];
const toStr = to.toISOString().split('T')[0];
return [{ json: { from: fromStr, to: toStr } }];

const item = $input.first().json;
let events = item.economicCalendar || item;
if (!Array.isArray(events)) events = [];
const highImpact = events
  .filter(e => (e.impact && e.impact.toLowerCase() === 'high') || (e.importance !== undefined && e.importance >= 2))
  .slice(0, 15);
const lines = highImpact.map(e => {
  const time = e.time ? new Date(e.time).toISOString().replace('T',' ').slice(0,16) : (e.date || '');
  const country = e.country || '';
  const event = e.event || e.title || e.name || 'Event';
  return `• ${time} [${country}] ${event}`;
});
const text = `📅 *Economic Calendar* (next 2 days, high impact)\n\n` + (lines.length ? lines.join('\n') : 'No high-impact events in range.');
return [{ json: { text, parse_mode: 'Markdown', count: highImpact.length } }];
